JS_CODE = 'let history = JSON.parse(localStorage.getItem(\'gasCalcHistory\') || \'[]\');\n\n  function setPrice(p) {\n    document.getElementById(\'gasolinePrice\').value = p;\n    document.querySelectorAll(\'.gas-price-btn\').forEach(b => b.classList.remove(\'active\'));\n    event.target.classList.add(\'active\');\n  }\n\n  function formatNum(n) {\n    return Math.round(n).toLocaleString(\'ja-JP\');\n  }\n\n  function calculate() {\n    const distance = parseFloat(document.getElementById(\'distance\').value) || 0;\n    const efficiency = parseFloat(document.getElementById(\'fuelEfficiency\').value) || 0;\n    const price = parseFloat(document.getElementById(\'gasolinePrice\').value) || 0;\n    if (!distance || !efficiency || !price) { alert(\'すべての値を入力してください\'); return; }\n    const liters = distance / efficiency;\n    const cost = liters * price;\n    const perKm = cost / distance;\n    document.getElementById(\'literResult\').textContent = liters.toFixed(2);\n    document.getElementById(\'costResult\').textContent = formatNum(cost);\n    document.getElementById(\'perKmResult\').textContent = perKm.toFixed(1);\n    document.getElementById(\'basicResult\').classList.remove(\'hidden\');\n    const entry = { date: new Date().toLocaleString(\'ja-JP\'), distance, efficiency, price, liters: liters.toFixed(2), cost: formatNum(cost) };\n    history.unshift(entry);\n    if (history.length > 10) history.pop();\n    localStorage.setItem(\'gasCalcHistory\', JSON.stringify(history));\n    renderHistory();\n  }\n\n  function simulate() {\n    const monthlyDist = parseFloat(document.getElementById(\'monthlyDistance\').value) || 0;\n    const efficiency = parseFloat(document.getElementById(\'fuelEfficiency\').value) || 0;\n    const price = parseFloat(document.getElementById(\'gasolinePrice\').value) || 0;\n    if (!monthlyDist || !efficiency || !price) { alert(\'燃費とガソリン単価も入力してください\'); return; }\n    const monthlyL = monthlyDist / efficiency;\n    const monthlyCost = monthlyL * price;\n    const yearlyL = monthlyL * 12;\n    const yearlyCost = monthlyCost * 12;\n    document.getElementById(\'monthlyResult\').textContent = formatNum(monthlyCost);\n    document.getElementById(\'yearlyResult\').textContent = formatNum(yearlyCost);\n    document.getElementById(\'monthlyLiter\').textContent = monthlyL.toFixed(1);\n    document.getElementById(\'yearlyLiter\').textContent = yearlyL.toFixed(1);\n    document.getElementById(\'simResult\').classList.remove(\'hidden\');\n    renderMonthlyChart(monthlyCost);\n  }\n\n  function renderMonthlyChart(monthlyCost) {\n    const months = [\'1月\',\'2月\',\'3月\',\'4月\',\'5月\',\'6月\',\'7月\',\'8月\',\'9月\',\'10月\',\'11月\',\'12月\'];\n    const multipliers = [0.95, 0.90, 1.00, 1.05, 1.10, 1.20, 1.25, 1.20, 1.05, 1.00, 0.95, 1.05];\n    const costs = multipliers.map(m => Math.round(monthlyCost * m));\n    const maxCost = Math.max(...costs);\n    let html = \'<h3 style="font-size:0.95rem;color:#a0c4ff;margin-bottom:0.8rem;">月別ガソリン代推定（夏冬補正あり）</h3>\';\n    months.forEach((m, i) => {\n      const pct = (costs[i] / maxCost * 100).toFixed(1);\n      html += `<div class="chart-bar-row"><div class="chart-bar-label">${m}</div><div class="chart-bar-bg"><div class="chart-bar-fill" style="width:${pct}%"></div></div><div class="chart-bar-val">¥${costs[i].toLocaleString()}</div></div>`;\n    });\n    document.getElementById(\'monthlyChart\').innerHTML = html;\n  }\n\n  function compareVehicles() {\n    const dist = parseFloat(document.getElementById(\'compareDistance\').value) || 0;\n    const price = parseFloat(document.getElementById(\'comparePrice\').value) || 0;\n    if (!dist || !price) { alert(\'値を入力してください\'); return; }\n    const vehicles = [\n      { name: \'軽自動車\', efficiency: 22, icon: \'🚗\' },\n      { name: \'コンパクトカー\', efficiency: 17, icon: \'🚙\' },\n      { name: \'セダン（普通）\', efficiency: 14, icon: \'🚘\' },\n      { name: \'ミニバン\', efficiency: 12, icon: \'🚐\' },\n      { name: \'SUV\', efficiency: 11, icon: \'🚙\' },\n      { name: \'大型ワゴン\', efficiency: 9, icon: \'🚌\' },\n      { name: \'ハイブリッド\', efficiency: 26, icon: \'⚡\' },\n      { name: \'EV（電費換算）\', efficiency: 35, icon: \'🔋\' },\n    ];\n    const costs = vehicles.m'
